content:
{
  "sentences": [
    {
      "text": "你好，我想要一杯小杯的拿鐵，麻煩你。",
      "pinyin": "Nǐ hǎo, wǒ xiǎng yào yī bēi xiǎo bēi de ná tiě, má fan nǐ.",
      "pinyin_numeric": "ni3 hao3, wo3 xiang3 yao4 yi1 bei1 xiao3 bei1 de5 na2 tie3, ma2 fan5 ni3.",
      "translation_en": "Hello, I would like a small latte, please.",
      "translation_ko": "안녕하세요, 작은 라떼 한 잔 주세요."
    },
    {
      "text": "請問，我可以看一下菜單嗎？",
      "pinyin": "Qǐng wèn, wǒ kě yǐ kàn yī xià cài dān ma?",
      "pinyin_numeric": "qing3 wen4, wo3 ke3 yi3 kan4 yi1 xia4 cai4 dan1 ma0?",
      "translation_en": "Excuse me, may I take a look at the menu?",
      "translation_ko": "실례합니다, 메뉴 좀 볼 수 있을까요?"
    },
    {
      "text": "我想要一杯紅茶，半糖，少冰，外帶。",
      "pinyin": "Wǒ xiǎng yào yī bēi hóng chá, bàn táng, shǎo bīng, wài dài.",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 hong2 cha2, ban4 tang2, shao3 bing1, wai4 dai4.",
      "translation_en": "I would like a black tea, half sugar, less ice, to go.",
      "translation_ko": "홍차 한 잔, 반당, 적은 얼음, 포장해 주세요."
    },
    {
      "text": "不好意思，可以給我一個袋子嗎？",
      "pinyin": "Bù hǎo yì si, kě yǐ gěi wǒ yī gè dài zi ma?",
      "pinyin_numeric": "bu4 hao3 yi4 si5, ke3 yi3 gei3 wo3 yi1 ge4 dai4 zi5 ma0?",
      "translation_en": "Excuse me, can you give me a bag?",
      "translation_ko": "죄송합니다, 봉투 하나 주실 수 있나요?"
    },
    {
      "text": "店員，請問這個價錢是多少？",
      "pinyin": "Diàn yuán, qǐng wèn zhè ge jià qián shì duō shǎo?",
      "pinyin_numeric": "dian4 yuan2, qing3 wen4 zhe4 ge5 jia4 qian2 shi4 duo1 shao3?",
      "translation_en": "Excuse me, clerk, how much is this?",
      "translation_ko": "점원님, 이 가격이 얼마인가요?"
    },
    {
      "text": "我想要一杯綠茶，加珍珠，正常甜，內用。",
      "pinyin": "Wǒ xiǎng yào yī bēi lǜ chá, jiā zhēn zhū, zhèng cháng tián, nèi yòng.",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 lü4 cha2, jia1 zhen1 zhu1, zheng4 chang2 tian2, nei4 yong4.",
      "translation_en": "I would like a green tea with boba, regular sweetness, for here.",
      "translation_ko": "녹차 한 잔에 타피오카 펄 추가, 보통 당도, 매장에서 먹을게요."
    },
    {
      "text": "可以幫我拿一根吸管嗎？謝謝。",
      "pinyin": "Kě yǐ bāng wǒ ná yī gēn xī guǎn ma? Xiè xiè.",
      "pinyin_numeric": "ke3 yi3 bang1 wo3 na2 yi1 gen1 xi1 guan3 ma0? xie4 xie5.",
      "translation_en": "Can you get me a straw? Thank you.",
      "translation_ko": "빨대 하나 가져다 주시겠어요? 감사합니다."
    },
    {
      "text": "不好意思，可以再說一次嗎？請慢一點。",
      "pinyin": "Bù hǎo yì si, kě yǐ zài shuō yī cì ma? Qǐng màn yī diǎn.",
      "pinyin_numeric": "bu4 hao3 yi4 si5, ke3 yi3 zai4 shuo1 yi1 ci4 ma0? qing3 man4 yi1 dian3.",
      "translation_en": "Excuse me, can you say that again? Please speak more slowly.",
      "translation_ko": "죄송합니다, 한 번 더 말씀해 주시겠어요? 천천히 말씀해 주세요."
    },
    {
      "text": "我想要一杯豆漿，大杯的，去冰，麻煩你。",
      "pinyin": "Wǒ xiǎng yào yī bēi dòu jiāng, dà bēi de, qù bīng, má fan nǐ.",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 dou4 jiang1, da4 bei1 de5, qu4 bing1, ma2 fan5 ni3.",
      "translation_en": "I would like a soy milk, large, no ice, please.",
      "translation_ko": "두유 한 잔, 큰 컵에 얼음 빼고 주세요."
    },
    {
      "text": "請問，可以等一下就拿到嗎？",
      "pinyin": "Qǐng wèn, kě yǐ děng yī xià jiù ná dào ma?",
      "pinyin_numeric": "qing3 wen4, ke3 yi3 deng3 yi1 xia4 jiu4 na2 dao4 ma0?",
      "translation_en": "Excuse me, can I get it in a moment?",
      "translation_ko": "실례합니다, 잠시 후에 받을 수 있나요?"
    }
  ]
}
